// v1.1 P1-2: Rejection feedback into prompt context.
// Pull past rejections for THIS lead + template combo (last 5) and feed them
// to Gemini as negative examples in the system prompt.
let past_rejections = [];
try {
  const allMsgs = $('Supabase: Get Conversation').all().map(i => i.json);
  past_rejections = allMsgs
    .filter(m => m.status === 'rejected' && m.rejection_reason)
    .slice(-5)
    .map(m => ({ reason: m.rejection_reason, draft: (m.content || '').slice(0, 200) }));
} catch (e) {
  past_rejections = [];
}

// Build the prompt context AND the Gemini request body for the Nurture draft
const lead = $('Supabase: Get Lead').first().json;

let score = null;
try { score = $('Supabase: Get Latest Score').first()?.json || null; } catch (e) { score = null; }

let property = null;
try { property = $('Supabase: Get Matched Property').first()?.json || null; } catch (e) { property = null; }

let conversation = [];
try {
  conversation = $('Supabase: Get Conversation').all().map(i => ({
    direction: i.json.direction,
    content: i.json.content,
    created_at: i.json.created_at
  }));
} catch (e) { conversation = []; }

const webhookBody = $('Webhook: Draft Message').first().json.body;

// v1.1 spec rev. 3 P0-1b — intent_gap_fill template.
// When desired_template === 'intent_gap_fill', we override the prompt with a
// qualification message that asks for the top ask_limit missing fields in
// priority order. The output is short, warm, project-specific, never invents
// facts, and gives the buyer easy reply options (ranges for budget, etc).
const _gapFillRequested = webhookBody.desired_template === 'intent_gap_fill';
const _missingFields = Array.isArray(webhookBody.missing_fields) ? webhookBody.missing_fields : [];
const _askLimit = Math.min(2, Math.max(1, webhookBody.ask_limit || 2));

// Priority-ordered field labels for the prompt.
const FIELD_LABELS = {
  purpose:            { label: 'are you looking to buy, rent, or invest',          example: 'buy / rent / invest' },
  budget_lakhs:       { label: 'what is your budget range',                          example: 'e.g. 80L-1.2Cr, 1.2-1.5Cr, 1.5Cr+' },
  purchase_timeline:  { label: 'when are you planning to move',                      example: 'Immediately / 3 months / 6 months / Exploring' },
  preferred_config:   { label: 'which configuration suits you',                      example: '1BHK / 2BHK / 3BHK / 4BHK' },
  preferred_locality: { label: 'which locality do you prefer',                       example: 'Hinjewadi / Baner / Wakad / Kharadi' },
  loan_status:        { label: 'how is your home loan progressing',                  example: 'Pre-approved / Applied / Planning / Not sure' },
};

const _topMissing = _missingFields.slice(0, _askLimit);
const _questionLines = _topMissing.map(f => {
  const meta = FIELD_LABELS[f];
  if (!meta) return null;
  return '- ' + meta.label + '? (' + meta.example + ')';
}).filter(Boolean).join('\n');






// Decide desired_template if not provided
let desired_template = webhookBody.desired_template;
if (!desired_template) {
  const action = score?.recommended_action;
  if (action === 'Schedule site visit') desired_template = 'site_visit_invite';
  else if (action === 'Send brochure')  desired_template = 'brochure_share';
  else if (action === 'Long-term nurture') desired_template = 'intake_qualifier';
  else desired_template = 'intake_qualifier';
}

const visit_slots = webhookBody.visit_slots || [];
const event_name = webhookBody.trigger_event || 'manual';

// Build the FULL Gemini request body as a JSON string. JSON.stringify escapes all
// newlines and quotes correctly, so this is always valid JSON. The HTTP node's JSON
// Body field must be in EXPRESSION mode referencing {{ $json.geminiBody }}.
const geminiBody = JSON.stringify({
  systemInstruction: { parts: [{ text: "You are the Nurture Drafting Agent for an Indian residential real estate sales platform. Draft a personalized WhatsApp message from a sales executive to a buyer. Ground every property fact ONLY in the MATCHED PROPERTY block; do not invent prices, possession, or amenities. Mirror the buyer's language: if language is 'hi', write in Hindi (Devanagari preferred). Length cap 480 chars. End with a single clear next step the buyer can answer in one tap. No marketing fluff. Output MUST be a single JSON object: { template_name, language, content, next_action }. No prose, no markdown fences." }] },
  contents: [{ role: "user", parts: [{ text: "LEAD:\n" + JSON.stringify(lead) + "\n\nLATEST SCORE:\n" + JSON.stringify(score) + "\n\nMATCHED PROPERTY (use ONLY these facts):\n" + JSON.stringify(property) + "\n\nCONVERSATION HISTORY:\n" + JSON.stringify(conversation) + "\n\nVISIT SLOTS:\n" + JSON.stringify(visit_slots) + "\n\nTRIGGER: " + event_name + "\nDESIRED TEMPLATE: " + desired_template + "\n\nDraft the message. Return ONLY the JSON." }] }],
  generationConfig: { temperature: 0.4, responseMimeType: "application/json" }
});


// Override the Gemini body for gap-fill drafts (qualification only, no selling).
if (_gapFillRequested) {
  const _projectName = (property && (property.project_name || property.name)) || 'your shortlisted project';
  const _leadFirstName = (lead && lead.name ? lead.name.split(' ')[0] : 'there');
  const _lang = (lead && lead.language) || 'en';
  const _systemText = 'You are drafting a SHORT WhatsApp qualification message in ' + (_lang === 'hi' ? 'Hindi (Devanagari script)' : 'English') + '. Goal: ask the buyer the listed missing fields. Hard rules: maximum 300 characters total; warm and human; mention the project name once; do NOT pitch or sell; ask only the listed fields; give an easy reply path (the examples in parentheses); never invent project facts. Respond with ONLY the message text, no JSON, no markdown.';
  const _userText = 'Buyer name: ' + _leadFirstName + '\nProject they enquired about: ' + _projectName + '\nQuestions to ask (' + _topMissing.length + '):\n' + _questionLines;
  geminiBody = JSON.stringify({
    systemInstruction: { parts: [{ text: _systemText }] },
    contents: [{ role: 'user', parts: [{ text: _userText }] }],
    generationConfig: { temperature: 0.3, maxOutputTokens: 200 }
  });
}

return [{
  json: { lead, score, property, conversation, visit_slots, desired_template, event_name, geminiBody }
}];

// Parse Gemini response, validate length + language. Defensive: never references nodes that may not have executed.
let lead;
try { lead = $('Supabase: Get Lead').first().json; } catch (e) { lead = ($json && $json.lead) ? $json.lead : {}; }

const resp = $('Gemini: Draft Message').first().json;

let draft;
try {
  const text = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  draft = JSON.parse(text);
} catch (e) {
  draft = {
    template_name: 'intake_qualifier',
    language: lead.language || 'en',
    content: (lead.language === 'hi')
      ? 'नमस्ते ' + (lead.name || '') + ' जी, आपकी रुचि के लिए धन्यवाद। कितने BHK और कितना बजट?'
      : 'Hi ' + (lead.name || 'there') + ', thanks for your interest. Which BHK and budget range works for you?',
    next_action: 'await_buyer_reply'
  };
}

if (typeof draft.content !== 'string' || draft.content.length > 480) {
  draft.content = (draft.content || '').slice(0, 480);
}
const expectedLang = lead.language || 'en';
if (draft.language !== expectedLang) draft.language = expectedLang;

return [{
  json: {
    lead_id: lead.id,
    lead_name: lead.name,
    lead_phone: lead.phone,
    template_name: draft.template_name || 'intake_qualifier',
    language: draft.language,
    content: draft.content,
    next_action: draft.next_action || 'await_buyer_reply'
  }
}];

// Build the final content (apply edit if action=edit_approve)
const body = $('Webhook: Approve Message').first().json.body;
const originalMsg = $('Supabase: Get Message').first().json;
const lead = $('Supabase: Get Lead (Approve flow)').first().json;
const finalContent = (body.action === 'edit_approve' && body.new_content) ? body.new_content : originalMsg.content;

// Twilio whatsapp:+E.164
const toNumber = 'whatsapp:' + (lead.phone || '').trim();

return [{
  json: {
    message_id: originalMsg.id,
    lead_id: lead.id,
    lead_phone: lead.phone,
    to: toNumber,
    body: finalContent,
    was_edited: body.action === 'edit_approve'
  }
}];
